import pytest
from stringkit import reverse, count_vowels, title_case, starts_with_vowel


class TestReverse:
    def test_reverse_simple(self):
        assert reverse("hello") == "olleh"

    def test_reverse_single_char(self):
        assert reverse("a") == "a"

    def test_reverse_empty(self):
        assert reverse("") == ""

    def test_reverse_palindrome(self):
        assert reverse("racecar") == "racecar"

    def test_reverse_with_spaces(self):
        assert reverse("hello world") == "dlrow olleh"

    def test_reverse_unicode(self):
        assert reverse("café") == "éfac"

    def test_reverse_numbers(self):
        assert reverse("12345") == "54321"


class TestCountVowels:
    def test_count_vowels_simple(self):
        assert count_vowels("hello") == 2

    def test_count_vowels_no_vowels(self):
        assert count_vowels("rhythm") == 0

    def test_count_vowels_all_vowels(self):
        assert count_vowels("aeiou") == 5

    def test_count_vowels_mixed_case(self):
        assert count_vowels("AEIOU") == 5

    def test_count_vowels_mixed_case2(self):
        assert count_vowels("Hello World") == 3

    def test_count_vowels_empty(self):
        assert count_vowels("") == 0

    def test_count_vowels_with_special_chars(self):
        assert count_vowels("hello@world!") == 3

    def test_count_vowels_y_not_vowel(self):
        # y is not considered a vowel in this implementation
        assert count_vowels("python") == 1


class TestTitleCase:
    def test_title_case_simple(self):
        assert title_case("hello world") == "Hello World"

    def test_title_case_single_word(self):
        assert title_case("hello") == "Hello"

    def test_title_case_empty(self):
        assert title_case("") == ""

    def test_title_case_already_title(self):
        assert title_case("Hello World") == "Hello World"

    def test_title_case_all_lowercase(self):
        assert title_case("the quick brown fox") == "The Quick Brown Fox"

    def test_title_case_mixed_case(self):
        assert title_case("hELLO wORLD") == "Hello World"

    def test_title_case_single_char(self):
        assert title_case("a") == "A"

    def test_title_case_multiple_spaces(self):
        # split() collapses multiple spaces into single space
        assert title_case("hello   world") == "Hello World"

    def test_title_case_leading_trailing_spaces(self):
        # split() removes leading/trailing whitespace
        assert title_case("  hello world  ") == "Hello World"

    def test_title_case_newlines(self):
        assert title_case("hello\nworld") == "Hello World"


class TestStartsWithVowel:
    def test_starts_with_vowel_simple(self):
        assert starts_with_vowel("apple") is True

    def test_starts_with_vowel_consonant(self):
        assert starts_with_vowel("banana") is False

    def test_starts_with_vowel_uppercase(self):
        assert starts_with_vowel("Apple") is True

    def test_starts_with_vowel_uppercase_consonant(self):
        assert starts_with_vowel("Banana") is False

    def test_starts_with_vowel_empty(self):
        assert starts_with_vowel("") is False

    def test_starts_with_vowel_special_char(self):
        assert starts_with_vowel("@apple") is False

    def test_starts_with_vowel_y(self):
        # y is not considered a vowel
        assert starts_with_vowel("yellow") is False

